function ExpandableText({ text, limit = 200, className = "" }) {
  const [isExpanded, setIsExpanded] = useState(false);
  const { t } = useLanguage();
  if (!text) return <p className={className}>{t("na") || "N/A"}</p>;

  const shouldShowToggle = text.length > limit;
  const displayText =
    isExpanded || !shouldShowToggle ? text : `${text.substring(0, limit)}...`;

  return (
    <div className={className}>
      <p
        style={{
          whiteSpace: "pre-line",
          margin: 0,
          color: "rgba(255,255,255,0.8)",
          fontSize: "14px",
          lineHeight: "1.6",
        }}>
        {displayText}
      </p>
      {shouldShowToggle && (
        <button
          onClick={() => setIsExpanded(!isExpanded)}
          className="mt-2 text-primary border-0 bg-transparent p-0"
          style={{
            fontSize: "13px",
            fontWeight: "600",
            cursor: "pointer",
            color: "#23ada4",
            transition: "all 0.2s",
          }}>
          {isExpanded ? t("viewLess") : t("viewMore")}
        </button>
      )}
    </div>
  );
}

